```typescript
// Importamos las herramientas de Firebase
import { getAuth, signInWithPopup, GoogleAuthProvider } from "firebase/auth";

const auth = getAuth(); // La instancia de seguridad
const provider = new GoogleAuthProvider(); // El proveedor (Google)

// Esta es la función que conectamos al botón
const loginConGoogle = async () => {
  try {
    // 1. Abrir la ventana mágica
    const result = await signInWithPopup(auth, provider);

    // 2. Google nos da la info del usuario
    const user = result.user; // Aquí está el email, foto, nombre...

    // 3. (Opcional) Token para acceder a APIs de Google Calendar/Drive si quisiéramos
    const credential = GoogleAuthProvider.credentialFromResult(result);
    const token = credential?.accessToken;

